class PaymentProcessor:
    def charge(self, amount: Decimal, payment_method: Dict) -> PaymentResult:
        if amount <= 0:
            raise PaymentProcessingError("Charge amount must be greater than zero.")
        if not payment_method or not payment_method.get("type"):
            raise PaymentProcessingError("Invalid payment method.")
        if payment_method.get("fail"):
            raise PaymentProcessingError("Payment was declined.")
        return PaymentResult(
            payment_id=str(uuid4()),
            status="paid",
            amount_charged=money(amount),
            provider=payment_method.get("provider", "mock_gateway"),
        )


