def validate_cart_items(user: User, cart_items: Sequence[CartItem]) -> ValidatedCart:
    if not cart_items:
        raise CartValidationError("Cart is empty.")

    validated_items: List[CartItem] = []
    subtotal = money("0.00")

    for item in cart_items:
        if item.quantity <= 0:
            raise CartValidationError(f"Invalid quantity for SKU {item.sku}.")
        if item.unit_price < 0:
            raise CartValidationError(f"Invalid unit price for SKU {item.sku}.")
        if not item.active:
            raise CartValidationError(f"Item {item.sku} is not available.")
        if item.stock < item.quantity:
            raise CartValidationError(f"Insufficient stock for SKU {item.sku}.")
        validated_items.append(item)
        subtotal += item.subtotal()

    return ValidatedCart(user=user, items=validated_items, subtotal=money(subtotal))


def apply_discount_code(
    validated_cart: ValidatedCart,
    discount_code: Optional[str],
    discount_catalog: Dict[str, DiscountCode],
) -> DiscountedCart:
    if not discount_code:
        return DiscountedCart(
            user=validated_cart.user,
            items=validated_cart.items,
            subtotal=validated_cart.subtotal,
            discount_code=None,
            discount_amount=money("0.00"),
            discounted_subtotal=validated_cart.subtotal,
        )

    code = discount_catalog.get(discount_code)
    if not code:
        raise DiscountValidationError("Discount code does not exist.")
    if not code.active:
        raise DiscountValidationError("Discount code is inactive.")
    if not code.is_user_allowed(validated_cart.user):
        raise DiscountPermissionError("User is not allowed to use this discount code.")
    if validated_cart.subtotal < money(code.min_subtotal):
        raise DiscountValidationError("Cart subtotal does not meet discount minimum.")

    if code.discount_type == "percent":
        discount_amount = validated_cart.subtotal * (code.value / Decimal("100"))
    elif code.discount_type == "fixed":
        discount_amount = code.value
    else:
        raise DiscountValidationError("Unsupported discount type.")

    discount_amount = money(min(discount_amount, validated_cart.subtotal))
    discounted_subtotal = money(validated_cart.subtotal - discount_amount)

    return DiscountedCart(
        user=validated_cart.user,
        items=validated_cart.items,
        subtotal=validated_cart.subtotal,
        discount_code=code.code,
        discount_amount=discount_amount,
        discounted_subtotal=discounted_subtotal,
    )


def calculate_tax(
    discounted_cart: DiscountedCart,
    tax_rate: Decimal,
    tax_strategy: Optional[Callable[[DiscountedCart, Decimal], Decimal]] = None,
) -> TaxedCart:
    tax_rate = Decimal(str(tax_rate))
    if tax_rate < 0:
        raise CheckoutError("Tax rate cannot be negative.")

    if tax_strategy:
        tax_amount = money(tax_strategy(discounted_cart, tax_rate))
    else:
        taxable_subtotal = money(
            sum((item.subtotal() for item in discounted_cart.items if item.taxable), Decimal("0.00"))
        )
        if discounted_cart.subtotal > 0 and taxable_subtotal > 0:
            ratio = taxable_subtotal / discounted_cart.subtotal
            discounted_taxable_base = money(discounted_cart.discounted_subtotal * ratio)
        else:
            discounted_taxable_base = money("0.00")
        tax_amount = money(discounted_taxable_base * tax_rate)

    total = money(discounted_cart.discounted_subtotal + tax_amount)

    return TaxedCart(
        user=discounted_cart.user,
        items=discounted_cart.items,
        subtotal=discounted_cart.subtotal,
        discount_code=discounted_cart.discount_code,
        discount_amount=discounted_cart.discount_amount,
        discounted_subtotal=discounted_cart.discounted_subtotal,
        tax_amount=tax_amount,
        total=total,
    )


def process_payment(
    taxed_cart: TaxedCart,
    payment_method: Dict,
    payment_processor: PaymentProcessor,
) -> PaymentResult:
    return payment_processor.charge(taxed_cart.total, payment_method)


def create_order_record(
    taxed_cart: TaxedCart,
    payment_result: PaymentResult,
    order_repository: OrderRepository,
) -> OrderRecord:
    order = OrderRecord(
        order_id=str(uuid4()),
        user_id=taxed_cart.user.user_id,
        created_at=datetime.utcnow().isoformat() + "Z",
        items=[
            {
                "sku": item.sku,
                "name": item.name,
                "unit_price": str(money(item.unit_price)),
                "quantity": item.quantity,
                "subtotal": str(item.subtotal()),
            }
            for item in taxed_cart.items
        ],
        subtotal=money(taxed_cart.subtotal),
        discount_code=taxed_cart.discount_code,
        discount_amount=money(taxed_cart.discount_amount),
        taxed_subtotal=money(taxed_cart.discounted_subtotal),
        tax_amount=money(taxed_cart.tax_amount),
        total=money(taxed_cart.total),
        payment_id=payment_result.payment_id,
        payment_status=payment_result.status,
    )
    return order_repository.create(order)


def checkout(
    user: User,
    cart_items: Sequence[CartItem],
    discount_code: Optional[str],
    payment_method: Dict,
    discount_catalog: Dict[str, DiscountCode],
    tax_rate: Decimal,
    payment_processor: Optional[PaymentProcessor] = None,
    order_repository: Optional[OrderRepository] = None,
    tax_strategy: Optional[Callable[[DiscountedCart, Decimal], Decimal]] = None,
) -> OrderRecord:
    payment_processor = payment_processor or PaymentProcessor()
    order_repository = order_repository or OrderRepository()

    validated_cart = validate_cart_items(user, cart_items)
    discounted_cart = apply_discount_code(validated_cart, discount_code, discount_catalog)
    taxed_cart = calculate_tax(discounted_cart, tax_rate, tax_strategy)
    payment_result = process_payment(taxed_cart, payment_method, payment_processor)
    return create_order_record(taxed_cart, payment_result, order_repository)


